python3 -c "
import csv
active = []
with open('market.csv', 'r') as f:
    reader = csv.DictReader(f)
    for row in reader:
        if row['is_resolved'] == 'False':
            active.append({
                'qid': row['qid'],
                'title': row['title'][:100],
                'res_date': row['resolution_date'],
                'pred': row['my_prediction'][:80] if row['my_prediction'] != '' else 'None',
            })

for q in sorted(active, key=lambda x: x['res_date'])[150:]:
    print(f\"{q['qid']}|{q['res_date']}|{q['title'][:85]}|{q['pred'][:60]}\")
" 2>&1
